Sure! Below is an example of a simple Discord bot using Discord.js v14 that includes a slash command to ban a user.

First, make sure you have Node.js installed on your system. Then, create a new directory for your bot and navigate into it. Initialize a new Node.js project and install the required dependencies:

```bash
mkdir my-discord-bot
cd my-discord-bot
npm init -y
npm install discord.js
```

Next, create a file named `index.js` and add the following code:

```javascript
const { Client, GatewayIntentBits, SlashCommandBuilder, REST, Routes } = require('discord.js');
require('dotenv').config();

const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.GuildBans,
  ],
});

const commands = [
  new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Bans a user from the server.')
    .addUserOption(option =>
      option.setName('user')
        .setDescription('The user to ban')
        .setRequired(true)
    )
    .addStringOption(option =>
      option.setName('reason')
        .setDescription('The reason for the ban')
        .setRequired(false)
    ),
].map(command => command.toJSON());

const rest = new REST({ version: '10' }).setToken(process.env.TOKEN);

(async () => {
  try {
    console.log('Started refreshing application (/) commands.');

    await rest.put(
      Routes.applicationCommands(process.env.CLIENT_ID),
      { body: commands },
    );

    console.log('Successfully reloaded application (/) commands.');
  } catch (error) {
    console.error(error);
  }
})();

client.once('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { commandName } = interaction;

  if (commandName === 'ban') {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    const member = interaction.guild.members.cache.get(user.id);
    if (member) {
      try {
        await member.ban({ reason });
        await interaction.reply(`${user.tag} has been banned. Reason: ${reason}`);
      } catch (error) {
        console.error(error);
        await interaction.reply('I was unable to ban the member.');
      }
    } else {
      await interaction.reply('That user is not in this server.');
    }
  }
});

client.login(process.env.TOKEN);
```

To keep your bot token and client ID secure, create a `.env` file in the root of your project and add:

```
TOKEN=YOUR_BOT_TOKEN
CLIENT_ID=YOUR_CLIENT_ID
```

Replace `YOUR_BOT_TOKEN` with your bot's token, and `YOUR_CLIENT_ID` with your application's client ID.

Finally, run your bot using:

```bash
node index.js
```

This bot will start up, register the `/ban` command, and listen for interactions. When a user uses the `/ban` command, it will attempt to ban the specified user from the server.

