```cpp
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Convert headers
    std::regex headerRegex("^(#{1,6})\\s*(.*)$", std::regex::multiline);
    html = std::regex_replace(html, headerRegex, [](const std::smatch& m) {
        int level = m[1].length();
        return "<h" + std::to_string(level) + ">" + m[2].str() + "</h" + std::to_string(level) + ">";
    });

    // Convert bold text
    std::regex boldRegex("\\*\\*(.*?)\\*\\*");
    html = std::regex_replace(html, boldRegex, "<strong>$1</strong>");

    // Convert italic text
    std::regex italicRegex("\\*(.*?)\\*");
    html = std::regex_replace(html, italicRegex, "<em>$1</em>");

    // Convert unordered lists
    std::regex ulRegex("^-\\s*(.*)$", std::regex::multiline);
    html = std::regex_replace(html, ulRegex, "<li>$1</li>");
    std::regex ulWrapperRegex("(<li>.*?</li>)", std::regex::dotall);
    html = std::regex_replace(html, ulWrapperRegex, "<ul>$1</ul>");

    // Convert ordered lists
    std::regex olRegex("^\\d+\\.\\s*(.*)$", std::regex::multiline);
    html = std::regex_replace(html, olRegex, "<li>$1</li>");
    std::regex olWrapperRegex("(<li>.*?</li>)", std::regex::dotall);
    html = std::regex_replace(html, olWrapperRegex, "<ol>$1</ol>");

    return html;
}

int main() {
    std::string markdownText = R"(
# Header 1
## Header 2
### Header 3

This is **bold** text and this is *italic* text.

- Item 1
- Item 2
- Item 3

1. First
2. Second
3. Third
)";

    std::string htmlText = markdownToHtml(markdownText);
    std::cout << htmlText << std::endl;

    return 0;
}
```

This function covers some basic Markdown to HTML conversions:

- Headers (`# Header`)
- Bold text (`**bold**`)
- Italic text (`*italic*`)
- Unordered lists (`- item`)
- Ordered lists (`1. item`)

Note that this implementation doesn't cover all Markdown features and edge cases. For a full Markdown to HTML conversion, you might consider using an existing library like `cmark` or `markdown-it-cpp` that implements the full Markdown specification.

Creating a smooth snake game in C with image-based animation involves several key steps. Here’s a basic outline and some guidance on how to approach it:

1. **Setup Development Environment**:
   - Ensure you have a C compiler installed (GCC is commonly used).
   - For handling graphics and images, you might want to use a library like SDL (Simple DirectMedia Layer).

2. **Install SDL Library**:
   - You can download SDL from [libsdl.org](https://www.libsdl.org/).
   - Follow the instructions to install it on your system.

3. **Initialize SDL and Create Window**:
   - Initialize SDL and create a window and renderer to draw your game.

4. **Load Assets**:
   - Load images for the snake, food, and background using SDL_image.

5. **Handle Game Logic**:
   - Implement the game loop to handle events, update game state, and render the screen.

6. **Game Loop**:
   - Handle input (e.g., keyboard events for snake control).
   - Update the snake's position.
   - Check for collisions (e.g., snake with food or walls).
   - Render the updated game state.

Here’s a simplified example to get you started:

```c
#include <SDL2/SDL.h>
#include <SDL2/SDL_image.h>
#include <stdbool.h>

#define WINDOW_WIDTH 640
#define WINDOW_HEIGHT 480
#define SNAKE_SIZE 20

typedef struct {
    int x, y;
} Segment;

typedef struct {
    Segment segments[100];
    int length;
    int dirX, dirY;
} Snake;

void render(SDL_Renderer *renderer, Snake *snake, SDL_Texture *snakeTexture) {
    for (int i = 0; i < snake->length; ++i) {
        SDL_Rect rect = { snake->segments[i].x, snake->segments[i].y, SNAKE_SIZE, SNAKE_SIZE };
        SDL_RenderCopy(renderer, snakeTexture, NULL, &rect);
    }
}

int main(int argc, char *argv[]) {
    SDL_Init(SDL_INIT_VIDEO);
    IMG_Init(IMG_INIT_PNG);
    SDL_Window *window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, WINDOW_WIDTH, WINDOW_HEIGHT, 0);
    SDL_Renderer *renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    SDL_Texture *snakeTexture = IMG_LoadTexture(renderer, "snake.png");

    Snake snake = { .length = 1, .dirX = SNAKE_SIZE, .dirY = 0 };
    snake.segments[0].x = WINDOW_WIDTH / 2;
    snake.segments[0].y = WINDOW_HEIGHT / 2;

    bool running = true;
    SDL_Event event;

    while (running) {
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                running = false;
            } else if (event.type == SDL_KEYDOWN) {
                switch (event.key.keysym.sym) {
                    case SDLK_UP:
                        snake.dirX = 0;
                        snake.dirY = -SNAKE_SIZE;
                        break;
                    case SDLK_DOWN:
                        snake.dirX = 0;
                        snake.dirY = SNAKE_SIZE;
                        break;
                    case SDLK_LEFT:
                        snake.dirX = -SNAKE_SIZE;
                        snake.dirY = 0;
                        break;
                    case SDLK_RIGHT:
                        snake.dirX = SNAKE_SIZE;
                        snake.dirY = 0;
                        break;
                }
            }
        }

        for (int i = snake.length - 1; i > 0; --i) {
            snake.segments[i] = snake.segments[i - 1];
        }
        snake.segments[0].x += snake.dirX;
        snake.segments[0].y += snake.dirY;

        SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
        SDL_RenderClear(renderer);

        render(renderer, &snake, snakeTexture);

        SDL_RenderPresent(renderer);

        SDL_Delay(100);  // Adjust this value for smoothness
    }

    SDL_DestroyTexture(snakeTexture);
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);

    IMG_Quit();
    SDL_Quit();

    return 0;
}
```

### Key Points:
- **SDL Initialization**: Initializes SDL and creates the main window and renderer.
- **Game Loop**: Polls for events, updates the snake's position, and renders the game state.
- **Rendering**: Uses `SDL_RenderCopy` to render the segments of the snake.
- **Texture Loading**: Loads a texture for the snake. You need to provide an image file named `snake.png`.

### Additional Features to Implement:
- **Food**: Add logic to place and render food, and detect when the snake eats it.
- **Collision Detection**: Check for collisions with walls and self.
- **Score and HUD**: Display the score and other game information.
- **Smooth Movement**: Adjust the delay in the game loop for smoother movement.

### Links and Resources:
- [SDL Documentation](https://wiki.libsdl.org/FrontPage)
- [Lazy Foo' Productions SDL Tutorials](http://lazyfoo.net/tutorials/SDL/index.php)

This example gives you a starting point. From here, you can expand and refine the game by adding more features and polishing the graphics and gameplay.

